/**
 * Curated fragrance catalog for rule-based recommendations.
 * Each fragrance has category, occasions, and budget so we can match gaps and quiz preferences.
 */

export type BudgetTier = "budget" | "mid" | "luxe" | "niche";
export type OccasionTag = "office" | "casual" | "date" | "formal" | "summer" | "evening";
export type CatalogGender = "masculine" | "feminine" | "unisex";

/** Price tier for recommendation scoring. */
export type PriceTier = "budget" | "designer" | "luxury" | "niche" | "ultra-niche";

/** Style cluster for recommendation scoring (e.g. fresh-clean, date-night). */
export type StyleCluster =
  | "fresh-clean"
  | "sweet-gourmand"
  | "dark-woody"
  | "spicy-oriental"
  | "luxury-niche"
  | "daily-office"
  | "date-night";

export interface CatalogFragrance {
  id: string;
  name: string;
  brand: string;
  category: string;
  occasions: OccasionTag[];
  budgetTier: BudgetTier;
  designerNiche: "designer" | "niche";
  /** Short descriptor for layering / matching (e.g. "citrus top", "woody base") */
  profileHint: string;
  /** Used to match genderPreference in recommendations. */
  gender: CatalogGender;
  /** Style cluster for scoring (fresh-clean, sweet-gourmand, dark-woody, etc.). */
  styleCluster: StyleCluster;
  /** Price tier (budget, designer, luxury, niche, ultra-niche). */
  priceTier: PriceTier;
  /** Scent accords (e.g. citrus, woody, floral). Optional for backward compatibility. */
  accords?: string[];
  /** Best seasons to wear. */
  seasons?: string[];
  /** Vibe / character (e.g. refined, bold, cozy). */
  vibe?: string;
  /** Longevity (e.g. moderate, long). */
  longevity?: string;
  /** Projection / sillage (e.g. intimate, moderate, strong). */
  projection?: string;
}

